const tipo = $('Router tipo mensaje').first().json.tipo;
const feedbackText = $('Router tipo mensaje').first().json.texto;
const sd = $getWorkflowStaticData('global');
const draft = sd['draft_' + chatId] || null;
const hasRealDraft = !!(draft && draft.toEmail && draft.cuerpo);

// Only allow regen path for explicit feedback with a real draft
const hasDraft = hasRealDraft && tipo === 'feedback';

return [{ json: { hasDraft, shouldSave: tipo === 'guardar_memoria', draft: draft || {}, feedbackText, chatId, tipo } }];

